import{_ as e,o as a,c as r,ag as n}from"./chunks/framework.BLeoozAw.js";const p=JSON.parse('{"title":"自动化兵器谱 (Modern Arsenal)","description":"从资产发现到自动漏扫，整合一线 SRC 专家的自动化武器库。","frontmatter":{"title":"自动化兵器谱 (Modern Arsenal)","description":"从资产发现到自动漏扫，整合一线 SRC 专家的自动化武器库。"},"headers":[],"relativePath":"tools/README.md","filePath":"tools/README.md"}'),o={name:"tools/README.md"};function l(i,t,s,c,h,d){return a(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="🛠️-自动化兵器谱-modern-arsenal" tabindex="-1">🛠️ 自动化兵器谱 (Modern Arsenal) <a class="header-anchor" href="#🛠️-自动化兵器谱-modern-arsenal" aria-label="Permalink to &quot;🛠️ 自动化兵器谱 (Modern Arsenal)&quot;">​</a></h1><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p><strong>工具即杠杆</strong>: 在现代 SRC 战场，速度决定收益。我们将渗透流程抽象为<strong>自动化流水线</strong>，每款工具都精准定位其在工程化中的坐标。</p></div><hr><h2 id="🛰️-资产发现与指纹-recon-fingerprinting" tabindex="-1">🛰️ 资产发现与指纹 (Recon &amp; Fingerprinting) <a class="header-anchor" href="#🛰️-资产发现与指纹-recon-fingerprinting" aria-label="Permalink to &quot;🛰️ 资产发现与指纹 (Recon &amp; Fingerprinting)&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">工具名称</th><th style="text-align:left;">核心能力</th><th style="text-align:left;">实战坐标</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><a href="https://github.com/projectdiscovery/naabu" target="_blank" rel="noreferrer">Naabu</a></strong></td><td style="text-align:left;">极速端口枚举</td><td style="text-align:left;">SYN/CONNECT 扫描，快速锁定开放服务</td></tr><tr><td style="text-align:left;"><strong><a href="https://github.com/projectdiscovery/httpx" target="_blank" rel="noreferrer">httpx</a></strong></td><td style="text-align:left;">多维指纹识别</td><td style="text-align:left;">探测技术栈、Web 容器版本，配合 retryablehttp 保证高并发</td></tr><tr><td style="text-align:left;"><strong><a href="https://github.com/devanshbatham/ParamSpider" target="_blank" rel="noreferrer">ParamSpider</a></strong></td><td style="text-align:left;">隐藏参数挖掘</td><td style="text-align:left;">从 Wayback Machine 等存档提取 URL，为 Fuzzing 提供弹药</td></tr></tbody></table><hr><h2 id="🧬-带外测试与漏洞捕获-oob-detection" tabindex="-1">🧬 带外测试与漏洞捕获 (OOB &amp; Detection) <a class="header-anchor" href="#🧬-带外测试与漏洞捕获-oob-detection" aria-label="Permalink to &quot;🧬 带外测试与漏洞捕获 (OOB &amp; Detection)&quot;">​</a></h2><ul><li><strong><a href="https://app.interactsh.com/" target="_blank" rel="noreferrer">Interactsh</a></strong>: 开源带外数据提取方案。检测 Blind SQLi, SSRF, CMDi 的金标准。</li><li><strong><a href="https://github.com/lijiejie/eyes.sh" target="_blank" rel="noreferrer">EYES</a></strong>: 深度优化的 DNSLog/HTTPLog 检测工具，适配国内主流扫描器。</li></ul><hr><h2 id="🔫-漏洞扫描与自动投弹-vuln-scanning" tabindex="-1">🔫 漏洞扫描与自动投弹 (Vuln Scanning) <a class="header-anchor" href="#🔫-漏洞扫描与自动投弹-vuln-scanning" aria-label="Permalink to &quot;🔫 漏洞扫描与自动投弹 (Vuln Scanning)&quot;">​</a></h2><h3 id="nuclei" tabindex="-1"><a href="https://github.com/projectdiscovery/nuclei" target="_blank" rel="noreferrer">Nuclei</a> <a class="header-anchor" href="#nuclei" aria-label="Permalink to &quot;[Nuclei](https://github.com/projectdiscovery/nuclei)&quot;">​</a></h3><p><strong>SRC 自动化的灵魂。</strong> 基于 YAML 模板的扫描器，支持 TCP/DNS/HTTP/Websocket 全协议。</p><ul><li><em>实战建议</em>: 维护一套自己的私有模板库，是冲击排行榜的关键。</li></ul><h3 id="afrog" tabindex="-1"><a href="https://github.com/zan8in/afrog" target="_blank" rel="noreferrer">afrog</a> <a class="header-anchor" href="#afrog" aria-label="Permalink to &quot;[afrog](https://github.com/zan8in/afrog)&quot;">​</a></h3><p>高性能漏洞扫描利器。内置大量 CVE, CNVD 以及针对国内大厂的未授权访问 PoC。</p><hr><h2 id="⚡-自动发现流-auto-discovery-pipeline" tabindex="-1">⚡ 自动发现流 (Auto-Discovery Pipeline) <a class="header-anchor" href="#⚡-自动发现流-auto-discovery-pipeline" aria-label="Permalink to &quot;⚡ 自动发现流 (Auto-Discovery Pipeline)&quot;">​</a></h2><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p><strong><a href="./auto-discovery/netlas-nuclei-auto.html">Netlas 侦察自动化 + Nuclei 自动扫描</a></strong> 深度整合 Netlas API 与 Python 脚本，实现从“子域发现”到“全自动化投弹”的端到端闭环。</p></div><hr><div class="caution custom-block github-alert"><p class="custom-block-title">CAUTION</p><p><strong>安全声明</strong>: 兵器库仅供合法的安全研究与 SRC 授权测试使用。请遵守相关法律法规，拒绝非法攻击。</p></div>',20)])])}const u=e(o,[["render",l]]);export{p as __pageData,u as default};
